@echo off
cd /d "%~dp0"
echo Current directory: %CD%
echo.

echo === Step 1: Deleting redundant and blank files ===
if exist docker-compose.example.yml (del /F docker-compose.example.yml && echo [DELETED] docker-compose.example.yml)
if exist SETUP-CREDENTIALS.md (del /F SETUP-CREDENTIALS.md && echo [DELETED] SETUP-CREDENTIALS.md)
if exist PRE-PUSH-CHECKLIST.md (del /F PRE-PUSH-CHECKLIST.md && echo [DELETED] PRE-PUSH-CHECKLIST.md)
if exist SECURITY-REVIEW.md (del /F SECURITY-REVIEW.md && echo [DELETED] SECURITY-REVIEW.md)
if exist remove-sensitive-files.bat (del /F remove-sensitive-files.bat && echo [DELETED] remove-sensitive-files.bat)
if exist inventoryservice\src\main\resources\application.properties.example (del /F inventoryservice\src\main\resources\application.properties.example && echo [DELETED] inventoryservice application.properties.example)
if exist bookingservice\src\main\resources\application.properties.example (del /F bookingservice\src\main\resources\application.properties.example && echo [DELETED] bookingservice application.properties.example)
if exist orderservice\src\main\resources\application.properties.example (del /F orderservice\src\main\resources\application.properties.example && echo [DELETED] orderservice application.properties.example)
if exist apigateway\src\main\resources\application.properties.example (del /F apigateway\src\main\resources\application.properties.example && echo [DELETED] apigateway application.properties.example)

echo.
echo === Step 2: Untracking sensitive files from Git ===
git rm --cached docker-compose.yml 2>nul && echo [UNTRACKED] docker-compose.yml || echo [SKIP] docker-compose.yml already untracked
git rm --cached inventoryservice\src\main\resources\application.properties 2>nul && echo [UNTRACKED] inventoryservice application.properties || echo [SKIP] inventoryservice application.properties already untracked
git rm --cached bookingservice\src\main\resources\application.properties 2>nul && echo [UNTRACKED] bookingservice application.properties || echo [SKIP] bookingservice application.properties already untracked
git rm --cached orderservice\src\main\resources\application.properties 2>nul && echo [UNTRACKED] orderservice application.properties || echo [SKIP] orderservice application.properties already untracked
git rm --cached apigateway\src\main\resources\application.properties 2>nul && echo [UNTRACKED] apigateway application.properties || echo [SKIP] apigateway application.properties already untracked
git rm --cached terraform.tfstate 2>nul && echo [UNTRACKED] terraform.tfstate || echo [SKIP] terraform.tfstate already untracked
git rm --cached terraform\terraform.tfstate 2>nul && echo [UNTRACKED] terraform\terraform.tfstate || echo [SKIP] terraform\terraform.tfstate already untracked
git rm --cached terraform\terraform.tfstate.backup 2>nul && echo [UNTRACKED] terraform\terraform.tfstate.backup || echo [SKIP] terraform backup already untracked
git rm -r --cached volume-data 2>nul && echo [UNTRACKED] volume-data directory || echo [SKIP] volume-data already untracked

echo.
echo === Step 3: Cleaning up script files ===
if exist untrack-sensitive.bat (del /F untrack-sensitive.bat && echo [DELETED] untrack-sensitive.bat)
if exist untrack-sensitive.sh (del /F untrack-sensitive.sh && echo [DELETED] untrack-sensitive.sh)

echo.
echo === All Done! ===
echo.
echo Summary:
echo - Deleted blank and redundant files
echo - Untracked sensitive files from Git
echo - Cleaned up temporary scripts
echo.
echo Next steps:
echo 1. git status (to see what changed)
echo 2. git add .
echo 3. git commit -m "Security: Untrack sensitive files and cleanup redundant files"
echo 4. git push origin main
echo.
echo This script will self-delete in 5 seconds...
timeout /t 5 /nobreak >nul
del /F "%~f0"

# PowerShell script to untrack sensitive files # Run this with: powershell -ExecutionPolicy Bypass -File .\cleanup.ps1
Set-Location "C:\Projects\Personal Java Projects\microservice3"
Write-Host "=== Current Directory ===" -ForegroundColor Cyan Get-Location Write-Host ""
Write-Host "=== Cleaning up extra files ===" -ForegroundColor Yellow $filesToDelete = @( "docker-compose.example.yml", "SETUP-CREDENTIALS.md", "PRE-PUSH-CHECKLIST.md", "SECURITY-REVIEW.md", "remove-sensitive-files.bat", "inventoryservice\src\main\resources\application.properties.example", "bookingservice\src\main\resources\application.properties.example", "orderservice\src\main\resources\application.properties.example", "apigateway\src\main\resources\application.properties.example" )
foreach ($file in $filesToDelete) { if (Test-Path $file) { Remove-Item $file -Force Write-Host "✓ Deleted: $file" -ForegroundColor Green } else { Write-Host "- Not found: $file" -ForegroundColor Gray } }
Write-Host "" Write-Host "=== Untracking sensitive files from Git ===" -ForegroundColor Yellow
$gitFiles = @( "docker-compose.yml", "inventoryservice\src\main\resources\application.properties", "bookingservice\src\main\resources\application.properties", "orderservice\src\main\resources\application.properties", "apigateway\src\main\resources\application.properties", "terraform.tfstate", "terraform\terraform.tfstate", "terraform\terraform.tfstate.backup" )
foreach ($file in $gitFiles) { $result = git rm --cached $file 2>&1 if ($LASTEXITCODE -eq 0) { Write-Host "✓ Untracked: $file" -ForegroundColor Green } else { Write-Host "- Not tracked: $file" -ForegroundColor Gray } }
# Untrack volume-data directory $result = git rm -r --cached volume-data 2>&1 if ($LASTEXITCODE -eq 0) { Write-Host "✓ Untracked: volume-data\" -ForegroundColor Green } else { Write-Host "- Not tracked: volume-data\" -ForegroundColor Gray }
Write-Host "" Write-Host "=== Done! ===" -ForegroundColor Green Write-Host "" Write-Host "Next steps:" -ForegroundColor Cyan Write-Host "1. git status" Write-Host "2. git add ." Write-Host "3. git commit -m 'Security: Untrack sensitive files'" Write-Host "4. git push origin main" Write-Host ""

@echo off
echo ========================================
echo   FINAL CLEANUP - Removing Redundant Files
echo ========================================
echo.

cd /d "%~dp0"

echo Keeping: README.md
echo Deleting all other documentation files...
echo.

REM Delete redundant MD files in root
if exist "RUN-THIS-FIRST.md" (del /F "RUN-THIS-FIRST.md" && echo [DELETED] RUN-THIS-FIRST.md)
if exist "HOW-TO-RUN.md" (del /F "HOW-TO-RUN.md" && echo [DELETED] HOW-TO-RUN.md)
if exist "SIMPLE-INSTRUCTIONS.md" (del /F "SIMPLE-INSTRUCTIONS.md" && echo [DELETED] SIMPLE-INSTRUCTIONS.md)
if exist "SECURITY-SETUP.md" (del /F "SECURITY-SETUP.md" && echo [DELETED] SECURITY-SETUP.md)
if exist "MONITORING-SETUP.md" (del /F "MONITORING-SETUP.md" && echo [DELETED] MONITORING-SETUP.md)

REM Delete redundant CMD file
if exist "COPY-PASTE-THIS.cmd" (del /F "COPY-PASTE-THIS.cmd" && echo [DELETED] COPY-PASTE-THIS.cmd)

REM Delete Spring Boot HELP.md files (auto-generated, not useful)
if exist "apigateway\HELP.md" (del /F "apigateway\HELP.md" && echo [DELETED] apigateway\HELP.md)
if exist "bookingservice\HELP.md" (del /F "bookingservice\HELP.md" && echo [DELETED] bookingservice\HELP.md)
if exist "inventoryservice\HELP.md" (del /F "inventoryservice\HELP.md" && echo [DELETED] inventoryservice\HELP.md)
if exist "orderservice\HELP.md" (del /F "orderservice\HELP.md" && echo [DELETED] orderservice\HELP.md)

echo.
echo --- Cleaning up script files ---
if exist "untrack-sensitive.bat" (del /F "untrack-sensitive.bat" && echo [DELETED] untrack-sensitive.bat)
if exist "untrack-sensitive.sh" (del /F "untrack-sensitive.sh" && echo [DELETED] untrack-sensitive.sh)
if exist "cleanup-and-untrack.bat" (del /F "cleanup-and-untrack.bat" && echo [DELETED] cleanup-and-untrack.bat)
if exist "final-cleanup.bat" (del /F "final-cleanup.bat" && echo [DELETED] final-cleanup.bat)
if exist "cleanup.ps1" (del /F "cleanup.ps1" && echo [DELETED] cleanup.ps1)

echo.
echo ========================================
echo   ✅ CLEANUP COMPLETE!
echo ========================================
echo.
echo Summary of what was kept:
echo   ✓ README.md (your main documentation)
echo   ✓ All source code files
echo   ✓ Configuration files
echo.
echo Summary of what was deleted:
echo   ✗ All redundant MD instruction files
echo   ✗ COPY-PASTE-THIS.cmd
echo   ✗ Spring Boot HELP.md files
echo   ✗ All cleanup scripts
echo.
echo Next steps:
echo   1. git status
echo   2. git add .
echo   3. git commit -m "Cleanup: Remove redundant documentation files"
echo   4. git push origin main
echo.
echo This script will self-delete in 5 seconds...
timeout /t 5 /nobreak >nul
del /F "%~f0"

@echo off
echo === Final Cleanup: Deleting script files ===
echo.

cd /d "%~dp0"

if exist untrack-sensitive.bat (
    del /F untrack-sensitive.bat
    echo [DELETED] untrack-sensitive.bat
) else (
    echo [NOT FOUND] untrack-sensitive.bat
)

if exist untrack-sensitive.sh (
    del /F untrack-sensitive.sh
    echo [DELETED] untrack-sensitive.sh
) else (
    echo [NOT FOUND] untrack-sensitive.sh
)

if exist cleanup-and-untrack.bat (
    del /F cleanup-and-untrack.bat
    echo [DELETED] cleanup-and-untrack.bat
) else (
    echo [NOT FOUND] cleanup-and-untrack.bat
)

echo.
echo === Cleanup Complete! ===
echo.
echo All temporary script files have been removed.
echo.
echo Next steps:
echo 1. Run: git status
echo 2. Run: git add .
echo 3. Run: git commit -m "Security: Untrack sensitive files and cleanup"
echo 4. Run: git push origin main
echo.
echo This script will self-delete in 3 seconds...
timeout /t 3 /nobreak >nul
del /F "%~f0"

# Minimal AWS ECR + ECS Setup for Testing
# Cost-optimized for US East 1 (Virginia)

provider "aws" {
  region = "us-east-1"  # Cheapest region
}

# ECR Repository (only one service for minimal cost)
resource "aws_ecr_repository" "apigateway" {
  name                 = "microservices-apigateway"
  image_tag_mutability = "MUTABLE"

  # Disable expensive features
  image_scanning_configuration {
    scan_on_push = false  # Saves cost
  }
}

# Use Default VPC (no additional cost)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# ECS Cluster (no cost for cluster itself)
resource "aws_ecs_cluster" "main" {
  name = "microservices-cluster"

  # Disable expensive monitoring
  setting {
    name  = "containerInsights"
    value = "disabled"
  }
}

# Security Group
resource "aws_security_group" "ecs_tasks" {
  name_prefix = "ecs-tasks-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 8080
    to_port     = 8080
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# IAM Role for ECS Tasks
resource "aws_iam_role" "ecs_task_role" {
  name = "ecs-task-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ecs-tasks.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role" "ecs_execution_role" {
  name = "ecs-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ecs-tasks.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ecs_execution_role_policy" {
  role       = aws_iam_role.ecs_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonECSTaskExecutionRolePolicy"
}

# ECS Task Definition - MINIMAL RESOURCES
resource "aws_ecs_task_definition" "apigateway" {
  family                   = "apigateway"
  network_mode             = "awsvpc"
  requires_compatibilities = ["FARGATE"]
  cpu                      = "256"    # Smallest possible
  memory                   = "512"    # Smallest possible
  execution_role_arn       = aws_iam_role.ecs_execution_role.arn
  task_role_arn           = aws_iam_role.ecs_task_role.arn

  container_definitions = jsonencode([
    {
      name      = "apigateway"
      image     = "${aws_ecr_repository.apigateway.repository_url}:latest"
      essential = true

      portMappings = [
        {
          containerPort = 8080
          protocol      = "tcp"
        }
      ]

      logConfiguration = {
        logDriver = "awslogs"
        options = {
          "awslogs-group"         = "/ecs/apigateway"
          "awslogs-region"        = "us-east-1"
          "awslogs-stream-prefix" = "ecs"
        }
      }
    }
  ])
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "apigateway" {
  name              = "/ecs/apigateway"
  retention_in_days = 1  # Minimal retention to save cost
}

# ECS Service - MINIMAL SCALE
resource "aws_ecs_service" "apigateway" {
  name            = "apigateway-service"
  cluster         = aws_ecs_cluster.main.id
  task_definition = aws_ecs_task_definition.apigateway.arn
  desired_count   = 1     # Only 1 instance
  launch_type     = "FARGATE"

  network_configuration {
    subnets          = data.aws_subnets.default.ids
    security_groups  = [aws_security_group.ecs_tasks.id]
    assign_public_ip = true  # For internet access without NAT Gateway cost
  }

  # Disable service discovery to save cost
  enable_execute_command = false
}

# Outputs
output "ecr_repository_url" {
  description = "ECR repository URL for pushing images"
  value       = aws_ecr_repository.apigateway.repository_url
}

output "ecs_cluster_name" {
  description = "ECS cluster name"
  value       = aws_ecs_cluster.main.name
}

output "aws_region" {
  description = "AWS region"
  value       = "us-east-1"
}

@echo off
cd /d "%~dp0"
echo Current directory: %CD%
echo.

echo === Cleaning up extra files ===
if exist docker-compose.example.yml (del docker-compose.example.yml && echo Deleted docker-compose.example.yml)
if exist SETUP-CREDENTIALS.md (del SETUP-CREDENTIALS.md && echo Deleted SETUP-CREDENTIALS.md)
if exist PRE-PUSH-CHECKLIST.md (del PRE-PUSH-CHECKLIST.md && echo Deleted PRE-PUSH-CHECKLIST.md)
if exist SECURITY-REVIEW.md (del SECURITY-REVIEW.md && echo Deleted SECURITY-REVIEW.md)
if exist remove-sensitive-files.bat (del remove-sensitive-files.bat && echo Deleted remove-sensitive-files.bat)
if exist inventoryservice\src\main\resources\application.properties.example (del inventoryservice\src\main\resources\application.properties.example && echo Deleted inventoryservice example)
if exist bookingservice\src\main\resources\application.properties.example (del bookingservice\src\main\resources\application.properties.example && echo Deleted bookingservice example)
if exist orderservice\src\main\resources\application.properties.example (del orderservice\src\main\resources\application.properties.example && echo Deleted orderservice example)
if exist apigateway\src\main\resources\application.properties.example (del apigateway\src\main\resources\application.properties.example && echo Deleted apigateway example)

echo.
echo === Untracking sensitive files from Git ===
git rm --cached docker-compose.yml 2>nul && echo Untracked docker-compose.yml
git rm --cached inventoryservice\src\main\resources\application.properties 2>nul && echo Untracked inventoryservice application.properties
git rm --cached bookingservice\src\main\resources\application.properties 2>nul && echo Untracked bookingservice application.properties
git rm --cached orderservice\src\main\resources\application.properties 2>nul && echo Untracked orderservice application.properties
git rm --cached apigateway\src\main\resources\application.properties 2>nul && echo Untracked apigateway application.properties
git rm --cached terraform.tfstate 2>nul && echo Untracked terraform.tfstate
git rm --cached terraform\terraform.tfstate 2>nul && echo Untracked terraform\terraform.tfstate
git rm --cached terraform\terraform.tfstate.backup 2>nul && echo Untracked terraform backup
git rm -r --cached volume-data 2>nul && echo Untracked volume-data

echo.
echo === Done! ===
echo.
echo Next steps:
echo 1. git status
echo 2. git add .
echo 3. git commit -m "Security: Untrack sensitive files"
echo 4. git push origin main
echo.
pause
